+  getForYouRecommendations,
+  getRelatedRecommendations,
+} from "../../src/search/recommendations";
+import type { Prompt } from "../../src/prompts/types";
+
+const basePrompt = {
+  description: "Test prompt description",
+  author: "Jeffrey Emanuel",
